        private static bool TryCreateHardcodedCommonScriptGuideContent(string assetPath, out StandardGuideContent content)
        {
            assetPath = NormalizeAssetPath(assetPath);
            string assetGuid = GetAssetGuidForHardcodedRule(assetPath);
            for (int i = 0; i < HardcodedCommonScriptGuideRules.Length; i++)
            {
                HardcodedScriptGuideRule rule = HardcodedCommonScriptGuideRules[i];
                if (!rule.Matches(assetPath, assetGuid))
                    continue;

                content = new StandardGuideContent(rule.ownerSystem, rule.roleTitle, rule.responsibilityHint, rule.readMe, rule.tags);
                return true;
            }

            content = null;
            return false;
        }

        private static string GetAssetGuidForHardcodedRule(string assetPath)
        {
#if UNITY_EDITOR
            return NormalizeGuid(AssetDatabase.AssetPathToGUID(assetPath));
#else
            return string.Empty;
#endif
        }

        private sealed class HardcodedScriptGuideRule
        {
            public readonly string path;
            public readonly string ownerSystem;
            public readonly string roleTitle;
            public readonly string responsibilityHint;
            public readonly string readMe;
            public readonly string[] tags;
            private string cachedGuid;

            public HardcodedScriptGuideRule(string path, string ownerSystem, string roleTitle, string responsibilityHint, string readMe, params string[] tags)
            {
                this.path = NormalizeAssetPath(path);
                this.ownerSystem = ownerSystem;
                this.roleTitle = roleTitle;
                this.responsibilityHint = responsibilityHint;
                this.readMe = readMe;
                this.tags = tags;
            }

            public bool Matches(string assetPath, string assetGuid)
            {
                string ruleGuid = GetRuleGuid();
                if (!string.IsNullOrEmpty(assetGuid) && !string.IsNullOrEmpty(ruleGuid))
                    return string.Equals(assetGuid, ruleGuid, StringComparison.OrdinalIgnoreCase);

                return assetPath.Equals(path, StringComparison.OrdinalIgnoreCase);
            }

            private string GetRuleGuid()
            {
                if (!string.IsNullOrEmpty(cachedGuid))
                    return cachedGuid;

#if UNITY_EDITOR
                cachedGuid = NormalizeGuid(AssetDatabase.AssetPathToGUID(path));
#else
                cachedGuid = string.Empty;
#endif
                return cachedGuid;
            }
        }

